import{_ as e,c as r,o as d,ae as t}from"./chunks/framework.Ye1pS4Qu.js";const u=JSON.parse('{"title":"从负载均衡访问K8S nodeport类型的pod的访问流程","description":"","frontmatter":{},"headers":[],"relativePath":"k8s/InterviewQuestions/procedure_of_accessing_nodeport_pods_from_load_balancer.md","filePath":"k8s/InterviewQuestions/procedure_of_accessing_nodeport_pods_from_load_balancer.md"}'),a={name:"k8s/InterviewQuestions/procedure_of_accessing_nodeport_pods_from_load_balancer.md"};function p(n,o,_,s,c,i){return d(),r("div",null,[...o[0]||(o[0]=[t('<h1 id="从负载均衡访问k8s-nodeport类型的pod的访问流程" tabindex="-1">从负载均衡访问K8S nodeport类型的pod的访问流程 <a class="header-anchor" href="#从负载均衡访问k8s-nodeport类型的pod的访问流程" aria-label="Permalink to &quot;从负载均衡访问K8S nodeport类型的pod的访问流程&quot;">​</a></h1><p>在NodePort的基础上，通过负载均衡器将外部流量分发到集群节点的NodePort上，再由kube-proxy转发到Service背后的Pod。</p><p>客户端请求先到达外部负载均衡器，</p><p>负载均衡将流量转发到某个Node节点的NodePort，</p><p>Node节点上的kube-proxy通过IPVS或iptables将请求转发到对应 Service，再根据 Service 的后端Endpoints将请求转发到具体 Pod，</p><p>最终由Pod内应用处理请求并返回响应。</p><h2 id="补充-nodeport类型的pod" tabindex="-1">补充：NodePort类型的pod <a class="header-anchor" href="#补充-nodeport类型的pod" aria-label="Permalink to &quot;补充：NodePort类型的pod&quot;">​</a></h2><p>Kubernetes会在每个节点上分配一个静态端口（范围通常为30000-32767），并将该端口上的流量转发到Service背后的Pod。</p>',8)])])}const f=e(a,[["render",p]]);export{u as __pageData,f as default};
